mapper.select:
SELECT * FROM user_verse_annotations
WHERE user_id = #{userId}
  AND version_id = #{versionId}
  AND book_id = #{bookId}
  AND chapter_number = #{chapterNumber}
  AND deleted_at IS NULL
ORDER BY start_verse ASC

SELECT * FROM user_verse_annotations
WHERE visibility = 'public'
  AND version_id = #{versionId}
  AND book_id = #{bookId}
  AND chapter_number = #{chapterNumber}
  AND deleted_at IS NULL
ORDER BY start_verse ASC, created_at DESC
